code.styles.css:
* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

html,
body {
  width: 100%;
  height: 100%;
  background-color: #f3f3f0;
  font-family: "Bagoss Standard TRIAL";
}

a {
  text-decoration: none;
  color: #000;
  font-size: 16px;
  font-weight: 500;
}

nav {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  padding: 2em;
  display: flex;
  justify-content: space-between;
  align-items: center;
  z-index: 1;
}

.nav-items {
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 2em;
}

.hero {
  position: absolute;
  top: 47.5%;
  left: 50%;
  transform: translate(-50%, -50%);
}

.hero h1 {
  font-family: "VTC Carrie";
  font-size: 15vw;
  line-height: 90%;
}

/* transition */
.transition {
  position: fixed;
  top: 0;
  left: 0;
  width: 100vw;
  height: 100vh;
  display: flex;
  flex-direction: column;
  z-index: 2;
  pointer-events: none;
}

.transition-row {
  flex: 1;
  display: flex;
}

.transition-row.row-1 .block {
  transform-origin: top;
}

.transition-row.row-2 .block {
  transform-origin: bottom;
}

.block {
  flex: 1;
  background-color: #746df8;
  transform: scaleY(1);
  will-change: transform;
  visibility: visible;
}

